#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define MAX_THREADS_PER_BLOCK 512

typedef struct Node {
    int starting;
    int no_of_edges;
} Node;

__kernel void BFS_1(__global Node* g_graph_nodes, __global int* g_graph_edges, __global char* g_graph_mask, __global char* g_updating_graph_mask, __global char* g_graph_visited, __global int* g_cost, int no_of_nodes)
{
    int tid = get_global_id(0);
    if (tid < no_of_nodes && g_graph_mask[tid])
    {
        g_graph_mask[tid] = 0;
        int start = g_graph_nodes[tid].starting;
        int end = start + g_graph_nodes[tid].no_of_edges;
        for(int i = start; i < end; i++)
        {
            int id = g_graph_edges[i];
            if(!g_graph_visited[id])
            {
                g_cost[id] = g_cost[tid] + 1;
                g_updating_graph_mask[id] = 1;
            }
        }
    }
}

__kernel void BFS_2(__global char* g_graph_mask, __global char* g_updating_graph_mask, __global char* g_graph_visited, __global char* g_over, int no_of_nodes)
{
    int tid = get_global_id(0);
    if (tid < no_of_nodes && g_updating_graph_mask[tid])
    {
        g_graph_mask[tid] = 1;
        g_graph_visited[tid] = 1;
        *g_over = 1;
        g_updating_graph_mask[tid] = 0;
    }
}
